arguments.argument:
if global.gamePaused=false
{
  if atkProg=0
  {
    circleRad-=1
    if circleRad<=0
    {
      bCanDealDamage=true
      atkProg=1
    }
  }
  else if atkProg=1
  {
    speed=bulletSpeed
    image_angle+=spinSpd
    decayTime-=1
    if decayTime<=0 {instance_destroy()}
  }
}
else {speed=0}
